const d = $input.first().json;
return [{ json: {
  success: true,
  data: {
    indicadores: {
      projetos_ativos: parseInt(d.projetos_ativos) || 0,
      projetos_concluidos: parseInt(d.projetos_concluidos) || 0,
      tarefas_abertas: parseInt(d.tarefas_abertas) || 0,
      tarefas_concluidas: parseInt(d.tarefas_concluidas) || 0
    },
    produtividade: d.produtividade || [],
    tarefas_por_status: d.tarefas_por_status || []
  }
}}];
